    38→/** Find the nearest ancestor directory containing package.json */
    39→function findPackageRoot(startDir: string): string {
    40→  let dir = startDir;
    41→  while (dir !== path.dirname(dir)) {
    42→    if (fs.existsSync(path.join(dir, "package.json"))) {
    43→      return dir;
    44→    }
    45→    dir = path.dirname(dir);
    46→  }
    47→  return startDir;
    48→}
