    10→  formatToolTitle,
    11→  resolveToolIcon,
    12→} from "../message-formatter.js";
    13→
    14→const DEBOUNCE_MS = 500;
    15→
    16→export interface ToolCardEntry {
    17→  id: string;
    18→  name: string;
    19→  kind?: string;
    20→  status: string;
    21→  icon: string;
    22→  label: string;
    23→  output?: string;
    24→  viewerLinks?: ViewerLinks;
    25→  viewerFilePath?: string;
    26→  hidden: boolean;
    27→}
    28→
    29→export interface UsageData {
    30→  tokensUsed?: number;
    31→  contextSize?: number;
    32→  cost?: number;
    33→}
    34→
    35→export interface ToolCardSnapshot {
    36→  entries: ToolCardEntry[];
    37→  planEntries?: PlanEntry[];
    38→  usage?: UsageData;
    39→  visibleCount: number;
    40→  totalVisible: number;
    41→  completedVisible: number;
    42→  allComplete: boolean;
    43→  verbosity: DisplayVerbosity;
    44→}
    45→
    46→export interface ToolCardStateConfig {
    47→  onFlush: (snapshot: ToolCardSnapshot) => void;
    48→  verbosity: DisplayVerbosity;
    49→}
    50→
    51→export class ToolCardState {
    52→  private entries: ToolCardEntry[] = [];
    53→  private planEntries?: PlanEntry[];
    54→  private usage?: UsageData;
    55→  private finalized = false;
    56→  private isFirstFlush = true;
    57→  private debounceTimer?: ReturnType<typeof setTimeout>;
    58→  private verbosity: DisplayVerbosity;
    59→  private onFlush: (snapshot: ToolCardSnapshot) => void;
    60→
    61→  constructor(config: ToolCardStateConfig) {
    62→    this.verbosity = config.verbosity;
    63→    this.onFlush = config.onFlush;
    64→  }
    65→
    66→  addTool(meta: ToolCallMeta, kind: string, rawInput: unknown): void {
    67→    if (this.finalized) return;
    68→
    69→    const hidden =
    70→      this.verbosity !== "high" &&
    71→      evaluateNoise(meta.name, kind, rawInput) !== null;
    72→    const entry: ToolCardEntry = {
    73→      id: meta.id,
    74→      name: meta.name,
    75→      kind,
    76→      status: meta.status ?? "running",
    77→      icon: resolveToolIcon({ status: meta.status ?? "running", kind }),
    78→      label:
    79→        this.verbosity === "low"
    80→          ? formatToolTitle(meta.name, rawInput, meta.displayTitle)
    81→          : formatToolSummary(meta.name, rawInput, meta.displaySummary),
    82→      viewerLinks: meta.viewerLinks,
    83→      viewerFilePath: meta.viewerFilePath,
    84→      hidden,
    85→    };
    86→    this.entries.push(entry);
    87→
    88→    if (this.isFirstFlush) {
    89→      this.isFirstFlush = false;
    90→      this.flush();
    91→    } else {
    92→      this.scheduleFlush();
    93→    }
    94→  }
    95→
    96→  updateTool(
    97→    id: string,
    98→    status: string,
    99→    viewerLinks?: ViewerLinks,
   100→    viewerFilePath?: string,
   101→    output?: string,
   102→    name?: string,
   103→    rawInput?: unknown,
   104→    displaySummary?: string,
   105→    displayTitle?: string,
   106→  ): void {
   107→    if (this.finalized) return;
   108→
   109→    const entry = this.entries.find((e) => e.id === id);
   110→    if (!entry) return;
   111→
   112→    entry.status = status;
   113→    entry.icon = resolveToolIcon({ status, kind: entry.kind });
   114→    if (viewerLinks) entry.viewerLinks = viewerLinks;
   115→    if (viewerFilePath) entry.viewerFilePath = viewerFilePath;
   116→    if (output !== undefined) entry.output = output;
   117→    if (name && rawInput !== undefined) {
   118→      entry.label =
   119→        this.verbosity === "low"
   120→          ? formatToolTitle(name, rawInput, displayTitle)
   121→          : formatToolSummary(name, rawInput, displaySummary);
   122→    }
   123→
   124→    this.scheduleFlush();
   125→  }
   126→
   127→  updatePlan(entries: PlanEntry[]): void {
   128→    if (this.finalized) return;
   129→    this.planEntries = entries;
   130→
   131→    if (this.entries.length === 0 && this.isFirstFlush) {
   132→      this.isFirstFlush = false;
   133→      this.flush();
   134→    } else {
   135→      this.scheduleFlush();
   136→    }
   137→  }
   138→
   139→  appendUsage(usage: UsageData): void {
   140→    // Allow post-finalize: usage event races with session_end, must not be dropped
   141→    this.usage = usage;
   142→    this.flush();
   143→  }
   144→
   145→  finalize(): void {
   146→    if (this.finalized) return;
   147→    this.finalized = true;
   148→    this.clearDebounce();
   149→    this.flush();
   150→  }
   151→
   152→  destroy(): void {
   153→    this.finalized = true;
   154→    this.clearDebounce();
   155→  }
   156→
   157→  hasContent(): boolean {
   158→    return this.entries.length > 0 || this.planEntries !== undefined;
   159→  }
   160→
   161→  private snapshot(): ToolCardSnapshot {
   162→    const visible = this.entries.filter((e) => !e.hidden);
   163→    const completedVisible = visible.filter(
   164→      (e) => e.status === "completed" || e.status === "done",
   165→    ).length;
   166→    const allComplete =
   167→      visible.length > 0 && completedVisible === visible.length;
   168→
   169→    return {
   170→      entries: this.entries,
   171→      planEntries: this.planEntries,
   172→      usage: this.usage,
   173→      visibleCount: visible.length,
   174→      totalVisible: visible.length,
   175→      completedVisible,
   176→      allComplete,
   177→      verbosity: this.verbosity,
   178→    };
   179→  }
   180→
