     1→import type { AgentEvent, OutgoingMessage } from "./types.js";
     2→import type { TunnelServiceInterface } from "./plugin/types.js";
     3→import { extractFileInfo } from "./utils/extract-file-info.js";
     4→import { createChildLogger } from "./utils/log.js";
     5→
     6→const log = createChildLogger({ module: "message-transformer" });
     7→
     8→export class MessageTransformer {
     9→  constructor(private tunnelService?: TunnelServiceInterface) {}
    10→
    11→  transform(
    12→    event: AgentEvent,
    13→    sessionContext?: { id: string; workingDirectory: string },
    14→  ): OutgoingMessage {
    15→    switch (event.type) {
    16→      case "text":
    17→        return { type: "text", text: event.content };
    18→      case "thought":
    19→        return { type: "thought", text: event.content };
    20→      case "tool_call": {
    21→        const meta = event.meta as Record<string, unknown> | undefined;
    22→        const metadata: Record<string, unknown> = {
    23→          id: event.id,
    24→          name: event.name,
    25→          kind: event.kind,
    26→          status: event.status,
    27→          content: event.content,
    28→          locations: event.locations,
    29→          rawInput: event.rawInput,
    30→          displaySummary: meta?.displaySummary,
    31→          displayTitle: meta?.displayTitle,
    32→          displayKind: meta?.displayKind,
    33→        };
    34→        this.enrichWithViewerLinks(event, metadata, sessionContext);
    35→        return { type: "tool_call", text: event.name, metadata };
    36→      }
    37→      case "tool_update": {
    38→        const meta = event.meta as Record<string, unknown> | undefined;
    39→        const metadata: Record<string, unknown> = {
    40→          id: event.id,
    41→          name: event.name,
    42→          kind: event.kind,
    43→          status: event.status,
    44→          content: event.content,
    45→          rawInput: event.rawInput,
    46→          rawOutput: event.rawOutput,
    47→          displaySummary: meta?.displaySummary,
    48→          displayTitle: meta?.displayTitle,
    49→          displayKind: meta?.displayKind,
    50→        };
    51→        this.enrichWithViewerLinks(event, metadata, sessionContext);
    52→        return { type: "tool_update", text: "", metadata };
    53→      }
    54→      case "plan":
    55→        return {
    56→          type: "plan",
    57→          text: "",
    58→          metadata: { entries: event.entries },
    59→        };
    60→      case "usage":
    61→        return {
    62→          type: "usage",
    63→          text: "",
    64→          metadata: {
    65→            tokensUsed: event.tokensUsed,
    66→            contextSize: event.contextSize,
    67→            cost: event.cost?.amount,
    68→          },
    69→        };
    70→      case "session_end":
    71→        return { type: "session_end", text: `Done (${event.reason})` };
    72→      case "error":
    73→        return { type: "error", text: event.message };
    74→      case "system_message":
    75→        return { type: "system_message", text: event.message };
    76→      case "session_info_update":
    77→        return {
    78→          type: "system_message",
    79→          text: `Session updated: ${event.title ?? ""}`.trim(),
    80→          metadata: { title: event.title, updatedAt: event.updatedAt },
    81→        };
    82→      case "current_mode_update":
    83→        return {
    84→          type: "mode_change",
    85→          text: `Mode: ${event.modeId}`,
    86→          metadata: { modeId: event.modeId },
    87→        };
    88→      case "config_option_update":
    89→        return {
    90→          type: "config_update",
    91→          text: "Config updated",
    92→          metadata: { options: event.options },
    93→        };
    94→      case "model_update":
    95→        return {
    96→          type: "model_update",
    97→          text: `Model: ${event.modelId}`,
    98→          metadata: { modelId: event.modelId },
    99→        };
   100→      case "user_message_chunk":
   101→        return {
   102→          type: "user_replay",
   103→          text: event.content,
   104→        };
   105→      case "resource_content":
   106→        return {
   107→          type: "resource",
   108→          text: event.name,
   109→          metadata: {
   110→            uri: event.uri,
   111→            text: event.text,
   112→            blob: event.blob,
   113→            mimeType: event.mimeType,
   114→          },
   115→        };
   116→      case "resource_link":
   117→        return {
   118→          type: "resource_link",
   119→          text: event.name,
   120→          metadata: {
   121→            uri: event.uri,
   122→            mimeType: event.mimeType,
   123→            title: event.title,
   124→            description: event.description,
   125→            size: event.size,
   126→          },
   127→        };
   128→      default:
   129→        return { type: "text", text: "" };
   130→    }
   131→  }
   132→
   133→  private enrichWithViewerLinks(
   134→    event: AgentEvent & { type: "tool_call" | "tool_update" },
   135→    metadata: Record<string, unknown>,
   136→    sessionContext?: { id: string; workingDirectory: string },
   137→  ): void {
   138→    if (!this.tunnelService || !sessionContext) return;
   139→
   140→    const name = "name" in event ? event.name || "" : "";
   141→    const kind = "kind" in event ? event.kind : undefined;
