  const session = this.core.sessionManager.getSession(sessionId);
  if (!session) return;
  await renameSessionTopic(
    this.bot,
    this.telegramConfig.chatId,
    Number(session.threadId),
    newName,
  );
  await this.core.sessionManager.patchRecord(sessionId, { name: newName });
}

